    23→}
    24→
    25→// Anchor-based timer: avoids comparing client clock with server timestamps.
    26→// anchorTime  = Date.now() at the moment we received server data
    27→// anchorTotal = total elapsed seconds (prior + session) at that moment
    28→// anchorBreak = break elapsed seconds at that moment (if on break)
    29→interface Anchor {
    30→  time: number;
    31→  total: number;
