    42→  const [busy, setBusy]         = useState(false);
    43→
    44→  const anchorRef = useRef<Anchor>({ time: Date.now(), total: 0, breakSec: 0, onBreak: false });
    45→  const tickRef   = useRef<ReturnType<typeof setInterval> | null>(null);
    46→
    47→  const startTick = useCallback((anchor: Anchor) => {
    48→    if (tickRef.current) clearInterval(tickRef.current);
    49→    tickRef.current = setInterval(() => {
    50→      const delta = Math.floor((Date.now() - anchorRef.current.time) / 1000);
    51→      if (anchorRef.current.onBreak) {
    52→        setBreakSec(anchorRef.current.breakSec + delta);
    53→        setElapsed(anchorRef.current.total); // frozen while on break
    54→      } else {
    55→        setElapsed(anchorRef.current.total + delta);
    56→        setBreakSec(0);
    57→      }
    58→    }, 1000);
    59→  }, []);
    60→
    61→  const setAnchor = useCallback((a: Anchor) => {
    62→    anchorRef.current = a;
    63→    if (a.onBreak) {
    64→      setBreakSec(a.breakSec);
    65→      setElapsed(a.total);
    66→    } else {
    67→      setElapsed(a.total);
    68→      setBreakSec(0);
    69→    }
    70→  }, []);
    71→
    72→  useEffect(() => {
    73→    setLoading(true);
    74→    api.shifts.active(managerName)
    75→      .then(({ active, session: s, todayPriorSeconds, sessionElapsedSeconds, breakElapsedSeconds }) => {
    76→        const prior   = todayPriorSeconds ?? 0;
    77→        const sessSec = sessionElapsedSeconds ?? 0;
    78→        const brkSec  = breakElapsedSeconds  ?? 0;
    79→
    80→        if (active && s) {
    81→          const onBreak = !!s.breakStartedAt;
    82→          const anchor: Anchor = {
    83→            time:     Date.now(),
    84→            total:    prior + sessSec,
    85→            breakSec: brkSec,
    86→            onBreak,
    87→          };
    88→          setSession(s);
    89→          setState(onBreak ? 'on_break' : 'active');
    90→          setAnchor(anchor);
    91→          startTick(anchor);
    92→          onShiftChange?.(true);
    93→        } else {
    94→          setElapsed(prior);
    95→          anchorRef.current = { time: Date.now(), total: prior, breakSec: 0, onBreak: false };
    96→          setState('idle');
    97→          onShiftChange?.(false);
    98→        }
    99→      })
   100→      .catch(() => {})
   101→      .finally(() => setLoading(false));
   102→    return () => { if (tickRef.current) clearInterval(tickRef.current); };
   103→  // eslint-disable-next-line react-hooks/exhaustive-deps
   104→  }, [managerName]);
   105→
   106→  const startShift = async () => {
   107→    setBusy(true);
   108→    try {
   109→      const { session: s, todayPriorSeconds, sessionElapsedSeconds } = await api.shifts.start(managerName);
   110→      const prior   = todayPriorSeconds    ?? 0;
   111→      const sessSec = sessionElapsedSeconds ?? 0;
   112→      const anchor: Anchor = { time: Date.now(), total: prior + sessSec, breakSec: 0, onBreak: false };
   113→      const pseudo = s ?? {
   114→        id: 0, managerName, startedAt: new Date().toISOString(),
   115→        endedAt: null, breakStartedAt: null, totalBreakSecs: 0,
   116→      };
   117→      setSession(pseudo);
   118→      setAnchor(anchor);
   119→      startTick(anchor);
   120→      setState('active');
   121→      onShiftChange?.(true);
   122→    } catch { /* ignore */ } finally { setBusy(false); }
   123→  };
   124→
   125→  const endShift = async () => {
   126→    setBusy(true);
   127→    try {
   128→      const { workedSeconds } = await api.shifts.end(managerName);
   129→      if (tickRef.current) clearInterval(tickRef.current);
   130→      const newTotal = anchorRef.current.total + (workedSeconds ?? 0);
   131→      anchorRef.current = { time: Date.now(), total: newTotal, breakSec: 0, onBreak: false };
   132→      setElapsed(newTotal);
   133→      setState('idle');
   134→      setSession(null);
   135→      setBreakSec(0);
   136→      onShiftChange?.(false);
   137→    } catch { /* ignore */ } finally { setBusy(false); }
   138→  };
   139→
   140→  const startBreak = async () => {
   141→    setBusy(true);
   142→    try {
   143→      await api.shifts.breakStart(managerName);
   144→      if (session) setSession({ ...session, breakStartedAt: new Date().toISOString() });
   145→      // Freeze total at current elapsed; begin counting break from 0
   146→      const nowTotal = anchorRef.current.onBreak
   147→        ? anchorRef.current.total
   148→        : anchorRef.current.total + Math.floor((Date.now() - anchorRef.current.time) / 1000);
   149→      const anchor: Anchor = { time: Date.now(), total: nowTotal, breakSec: 0, onBreak: true };
   150→      setAnchor(anchor);
   151→      startTick(anchor);
   152→      setState('on_break');
   153→    } catch { /* ignore */ } finally { setBusy(false); }
   154→  };
   155→
   156→  const endBreak = async () => {
   157→    setBusy(true);
   158→    try {
   159→      await api.shifts.breakEnd(managerName);
   160→      if (session) setSession({ ...session, breakStartedAt: null });
   161→      // Resume counting work time from the frozen total
   162→      const anchor: Anchor = { time: Date.now(), total: anchorRef.current.total, breakSec: 0, onBreak: false };
   163→      setAnchor(anchor);
   164→      startTick(anchor);
   165→      setState('active');
   166→      setBreakSec(0);
   167→    } catch { /* ignore */ } finally { setBusy(false); }
   168→  };
   169→
   170→  if (loading) return <div className="mx-5 mb-1 h-10 rounded-xl bg-neutral-100/50 animate-pulse" />;
   171→
   172→  // ── IDLE ─────────────────────────────────────────────────────────────────
   173→  if (state === 'idle') return (
   174→    <div className="px-5 mb-1 space-y-2">
