   184→      >
   185→        <Play className="w-3 h-3" />
   186→        {elapsed > 0 ? 'Продолжить смену' : 'Начать смену'}
   187→      </button>
   188→    </div>
   189→  );
   190→
   191→  // ── ACTIVE ────────────────────────────────────────────────────────────────
   192→  if (state === 'active') return (
   193→    <div className="px-5 mb-1 space-y-2">
   194→      <div className="flex items-center justify-between px-3 py-2.5 rounded-xl bg-white/50 border border-neutral-200/60 shadow-3xs">
   195→        <div className="flex items-center gap-2">
   196→          <span className="relative flex w-2 h-2">
   197→            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75" />
   198→            <span className="relative inline-flex rounded-full w-2 h-2 bg-emerald-500" />
   199→          </span>
   200→          <span className="text-[9.5px] font-extrabold uppercase tracking-widest text-neutral-700">На смене</span>
   201→        </div>
   202→        <span className="font-mono text-[11px] font-bold text-neutral-900 tabular-nums">{fmt(elapsed)}</span>
   203→      </div>
   204→      {session && (
   205→        <p className="text-[9px] text-neutral-400 text-center font-medium">
   206→          сессия с {mskHHMM(session.startedAt)} МСК
   207→        </p>
   208→      )}
   209→      <div className="grid grid-cols-2 gap-1.5">
   210→        <button
   211→          onClick={startBreak} disabled={busy}
   212→          className="flex items-center justify-center gap-1.5 py-2 rounded-xl border border-neutral-200/70 bg-white/50 hover:bg-amber-50 hover:border-amber-200 hover:text-amber-700 text-neutral-500 text-[9px] font-bold uppercase tracking-widest transition-all duration-150 cursor-pointer active:scale-[0.98] disabled:opacity-40"
   213→        >
   214→          <Coffee className="w-3 h-3" />
   215→          Перерыв
   216→        </button>
   217→        <button
   218→          onClick={endShift} disabled={busy}
   219→          className="flex items-center justify-center gap-1.5 py-2 rounded-xl border border-neutral-200/70 bg-white/50 hover:bg-red-50 hover:border-red-200 hover:text-red-600 text-neutral-500 text-[9px] font-bold uppercase tracking-widest transition-all duration-150 cursor-pointer active:scale-[0.98] disabled:opacity-40"
   220→        >
   221→          <StopCircle className="w-3 h-3" />
   222→          Завершить
   223→        </button>
   224→      </div>
   225→    </div>
   226→  );
   227→
   228→  // ── ON BREAK ──────────────────────────────────────────────────────────────
   229→  return (
   230→    <div className="px-5 mb-1 space-y-2">
   231→      <div className="flex items-center justify-between px-3 py-2.5 rounded-xl bg-white/50 border border-amber-200/60 shadow-3xs">
   232→        <div className="flex items-center gap-2">
