    24→function fmtDate(dateStr: string): string {
    25→  const [y, m, d] = dateStr.split('-').map(Number);
    26→  const dt = new Date(y, m - 1, d);
    27→  return dt.toLocaleDateString('ru-RU', { day: 'numeric', month: 'long', year: 'numeric', weekday: 'long' });
    28→}
    29→
    30→function prevDay(d: string): string {
    31→  const dt = new Date(d + 'T00:00:00');
    32→  dt.setDate(dt.getDate() - 1);
    33→  return dt.toLocaleDateString('sv');
