    44→  const breaks = s.totalBreakSecs * 1000
    45→    + (s.breakStartedAt ? Date.now() - new Date(s.breakStartedAt).getTime() : 0);
    46→  return Math.max(0, Math.floor((gross - breaks) / 1000));
    47→}
