     4→const router = Router();
     5→
     6→const ONLINE_THRESHOLD_MS = 3 * 60 * 1000;
     7→
     8→function deriveStatus(lastSeenAt: Date | null): 'online' | 'offline' {
     9→  if (!lastSeenAt) return 'offline';
    10→  return (Date.now() - lastSeenAt.getTime()) < ONLINE_THRESHOLD_MS ? 'online' : 'offline';
    11→}
    12→
    13→const MSK = 'Europe/Moscow';
    14→
    15→function toMskTime(date: Date): string {
    16→  return date.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit', timeZone: MSK });
    17→}
    18→
    19→function toMskDate(date: Date): string {
    20→  return date.toLocaleDateString('ru-RU', { day: 'numeric', month: 'short', timeZone: MSK });
    21→}
    22→
    23→function formatLastSeen(lastSeenAt: Date | null): string {
    24→  if (!lastSeenAt) return 'Не в сети';
    25→  const diffMs = Date.now() - lastSeenAt.getTime();
    26→  if (diffMs < 0) return 'Не в сети';
    27→  if (diffMs < ONLINE_THRESHOLD_MS) return 'В сети';
    28→  const diffMin = Math.floor(diffMs / 60_000);
    29→  if (diffMin < 60) return `${diffMin} мин назад`;
    30→  const diffH = Math.floor(diffMin / 60);
    31→  if (diffH < 24) return `был(а) в ${toMskTime(lastSeenAt)} МСК`;
    32→  const diffD = Math.floor(diffH / 24);
    33→  if (diffD === 1) return `вчера в ${toMskTime(lastSeenAt)} МСК`;
    34→  if (diffD < 7) return `${diffD} дня назад в ${toMskTime(lastSeenAt)} МСК`;
    35→  return `${toMskDate(lastSeenAt)} в ${toMskTime(lastSeenAt)} МСК`;
    36→}
    37→
    38→function mapRow(row: any) {
    39→  const lastSeenAt: Date | null = row.last_seen_at ? new Date(row.last_seen_at) : null;
    40→  const status = deriveStatus(lastSeenAt);
    41→  return {
    42→    id: row.id ? Number(row.id) : undefined,
    43→    name: row.name,
    44→    role: row.role,
    45→    pin: row.pin,
    46→    department: row.department,
    47→    status,
    48→    lastActive: formatLastSeen(lastSeenAt),
    49→  };
    50→}
    51→
    52→function dbRequired(res: any) {
    53→  return res.status(503).json({ error: 'База данных недоступна' });
    54→}
