    57→router.get('/', async (_req, res) => {
    58→  if (!db.pool || !db.isConnected) return dbRequired(res);
    59→  try {
    60→    const result = await db.pool.query('SELECT * FROM marketing_users ORDER BY name ASC');
    61→    return res.json(result.rows.map(mapRow));
    62→  } catch (err: any) {
    63→    return res.status(500).json({ error: err.message });
    64→  }
    65→});
    66→
    67→// POST /api/users
    68→router.post('/', async (req, res) => {
    69→  const { id, name, role, pin, department, originalName } = req.body;
    70→  if (!name || !role || !pin) {
    71→    return res.status(400).json({ error: 'ФИО, роль и ПИН-код обязательны' });
